    public static class SyntaxError {
        public final String type;
        public final String message;
        public final int line;
        public final int column;
        public final String lexeme;

        public SyntaxError(String type, String message, int line, int column, String lexeme) {
            this.type = type;
            this.message = message;
            this.line = line;
            this.column = column;
            this.lexeme = lexeme;
        }

        @Override
        public String toString() {
            return "<" + type + ": " + message +
                   " en línea " + line +
                   ", columna " + column +
                   ", cerca de '" + lexeme + "' />";
        }
    }

    private final List<SyntaxError> syntaxErrors = new ArrayList<>();

    public List<SyntaxError> getSyntaxErrors() {
        return syntaxErrors;
    }

    private void addSyntaxError(Symbol token, String message) {
        String lexeme = "EOF";
        int line = -1;
        int column = -1;

        if (token != null) {
            if (token.value != null) {
                lexeme = token.value.toString();
            }
            line = token.left;
            column = token.right;
        }

        addSyntaxError(line, column, lexeme, message);
    }

    private void addSyntaxError(int line, int column, String lexeme, String message) {
        if (lexeme == null || lexeme.isBlank()) {
            lexeme = "desconocido";
        }

        if (!syntaxErrors.isEmpty()) {
            SyntaxError last = syntaxErrors.get(syntaxErrors.size() - 1);
            if (last.line == line &&
                last.column == column &&
                last.lexeme.equals(lexeme) &&
                last.message.equals(message)) {
                return;
            }
        }

        syntaxErrors.add(new SyntaxError(
            "Sintáctico",
            message,
            line,
            column,
            lexeme
        ));
    }

    @Override
    public void syntax_error(Symbol cur_token) {
        addSyntaxError(cur_token, "Símbolo inesperado");
    }

    @Override
    public void unrecovered_syntax_error(Symbol cur_token) throws Exception {
        addSyntaxError(cur_token, "Error sintáctico no recuperable");
    }

    @Override
    public void report_error(String message, Object info) {
        if (info instanceof Symbol) {
            addSyntaxError((Symbol) info, message);
        } else {
            addSyntaxError(-1, -1, "desconocido", message);
        }
    }

    @Override
    public void report_fatal_error(String message, Object info) throws Exception {
        report_error(message, info);
        throw new Exception(message);
    }


